import { useState } from "react";

export default function Administer() {
  const [form, setForm] = useState({});

  const submit = async () => {
    await fetch("http://10.250.12.50:5000/administer", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(form),
    });

    alert("Dose Recorded & Certificate Generated");
  };

  return (
    <div className="card">
  <h2>💉 Record Vaccination</h2>

  <input placeholder="Citizen ID" />
  <input placeholder="Dose Number" />
  <input placeholder="Center ID" />

  <button>Record Dose</button>
</div>
  );
}
